    <style>
        @import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700&family=Roboto:wght@300;400;700&display=swap');

        :root {
            --dark-bg: #000000;
            --dark-panel: #0a0a0a;
            --neon-blue: #00f3ff;
            --neon-purple: #b026ff;
            --neon-green: #00ff99;
            --text-light: #e0e0e0;
            --text-accent: #f8f8f8;
            --border-glow-blue: 0 0 10px var(--neon-blue), 0 0 20px var(--neon-blue);
            --border-glow-purple: 0 0 10px var(--neon-purple), 0 0 20px var(--neon-purple);
            --text-glow-blue: 0 0 5px var(--neon-blue), 0 0 10px var(--neon-blue);
            --text-glow-purple: 0 0 5px var(--neon-purple), 0 0 10px var(--neon-purple);
            --text-glow-green: 0 0 5px var(--neon-green), 0 0 10px var(--neon-green);
        }

        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
            font-family: 'Roboto', 'Segoe UI', sans-serif; /* Fallback for Orbitron */
        }

        body {
            background: radial-gradient(ellipse at center, #0a0a0a 0%, #000000 100%);
            color: var(--text-light);
            min-height: 100vh;
            display: flex;
            align-items: center;
            justify-content: center;
            overflow: hidden; /* Prevent scrollbar from animation */
            padding: 20px;
        }

        .dashboard-container {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            grid-template-rows: repeat(3, 1fr);
            gap: 25px;
            width: 95vw;
            height: 95vh;
            max-width: 1920px;
            max-height: 1080px;
            position: relative;
            perspective: 1000px;
        }

        .dashboard-container::before {
            content: '';
            position: absolute;
            top: -20px;
            left: -20px;
            right: -20px;
            bottom: -20px;
            border: 2px solid rgba(0, 243, 255, 0.3);
            box-shadow: 0 0 40px rgba(0, 243, 255, 0.5), inset 0 0 40px rgba(0, 243, 255, 0.5);
            pointer-events: none;
            z-index: -1;
            animation: borderGlow 4s infinite alternate ease-in-out;
        }

        @keyframes borderGlow {
            from {
                border-color: rgba(0, 243, 255, 0.3);
                box-shadow: 0 0 40px rgba(0, 243, 255, 0.5), inset 0 0 40px rgba(0, 243, 255, 0.5);
            }
            to {
                border-color: rgba(176, 38, 255, 0.4);
                box-shadow: 0 0 60px rgba(176, 38, 255, 0.6), inset 0 0 60px rgba(176, 38, 255, 0.6);
            }
        }

        .dashboard-block {
            background-color: var(--dark-panel);
            border: 1px solid rgba(0, 243, 255, 0.2);
            padding: 25px;
            border-radius: 8px;
            box-shadow: var(--border-glow-blue);
            transition: all 0.3s ease-in-out;
            position: relative;
            overflow: hidden;
            display: flex;
            flex-direction: column;
        }

        .dashboard-block::before {
            content: '';
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: linear-gradient(45deg, transparent 49%, rgba(0, 243, 255, 0.05) 50%, transparent 51%);
            background-size: 100% 100%;
            opacity: 0.2;
            pointer-events: none;
            z-index: 0;
        }

        .dashboard-block:hover {
            transform: translateY(-5px) scale(1.01);
            border-color: var(--neon-purple);
            box-shadow: var(--border-glow-purple);
            z-index: 10;
        }

        .dashboard-block h2 {
            font-family: 'Orbitron', sans-serif;
            color: var(--neon-blue);
            text-shadow: var(--text-glow-blue);
            margin-bottom: 15px;
            font-size: 1.5em;
            letter-spacing: 1px;
            position: relative;
            z-index: 1;
        }

        .dashboard-block:nth-child(even) h2 {
            color: var(--neon-purple);
            text-shadow: var(--text-glow-purple);
        }
        .dashboard-block:nth-child(odd) h2 {
            color: var(--neon-blue);
            text-shadow: var(--text-glow-blue);
        }

        .dashboard-block ul {
            list-style: none;
            padding-left: 0;
            margin-top: 10px;
            flex-grow: 1;
            overflow-y: auto; /* Scroll for long content */
            scrollbar-width: thin;
            scrollbar-color: var(--neon-blue) var(--dark-panel);
            position: relative;
            z-index: 1;
        }

        .dashboard-block ul::-webkit-scrollbar {
            width: 8px;
        }

        .dashboard-block ul::-webkit-scrollbar-track {
            background: var(--dark-panel);
        }

        .dashboard-block ul::-webkit-scrollbar-thumb {
            background-color: var(--neon-blue);
            border-radius: 4px;
            border: 2px solid var(--dark-panel);
        }

        .dashboard-block li {
            position: relative;
            padding-left: 25px;
            margin-bottom: 10px;
            line-height: 1.6;
            font-size: 0.95em;
            color: var(--text-light);
        }

        .dashboard-block li::before {
            content: '›'; /* Cyberpunk bullet point */
            position: absolute;
            left: 0;
            color: var(--neon-green);
            font-weight: bold;
            text-shadow: var(--text-glow-green);
            font-size: 1.2em;
        }

        /* Specific block positioning */
        .main-trend {
            grid-column: 2 / 3; /* Center column */
            grid-row: 2 / 3;    /* Center row */
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            text-align: center;
            padding: 40px;
            border: 2px solid var(--neon-blue);
            box-shadow: 0 0 20px var(--neon-blue), 0 0 40px var(--neon-blue), inset 0 0 20px var(--neon-blue);
            background: radial-gradient(circle at center, rgba(0, 243, 255, 0.05) 0%, var(--dark-panel) 70%);
            animation: mainGlow 3s infinite alternate ease-in-out;
            z-index: 50; /* Ensure it's on top */
        }

        @keyframes mainGlow {
            from {
                border-color: var(--neon-blue);
                box-shadow: 0 0 20px var(--neon-blue), 0 0 40px var(--neon-blue), inset 0 0 20px var(--neon-blue);
            }
            to {
                border-color: var(--neon-purple);
                box-shadow: 0 0 30px var(--neon-purple), 0 0 60px var(--neon-purple), inset 0 0 30px var(--neon-purple);
            }
        }

        .main-trend h1 {
            font-family: 'Orbitron', sans-serif;
            font-size: 3em;
            color: var(--neon-green);
            text-shadow: var(--text-glow-green);
            margin-bottom: 25px;
            letter-spacing: 2px;
        }

        .main-trend ul {
            max-width: 80%;
            margin: 0 auto;
            font-size: 1.1em;
            line-height: 1.8;
            color: var(--text-accent);
            text-align: left;
        }

        .main-trend li::before {
            color: var(--neon-blue);
            text-shadow: var(--text-glow-blue);
        }

        /* Positioning for surrounding blocks */
        .block-1 { grid-column: 1 / 2; grid-row: 1 / 2; } /* Top-Left */
        .block-2 { grid-column: 3 / 4; grid-row: 1 / 2; } /* Top-Right */
        .block-3 { grid-column: 1 / 2; grid-row: 3 / 4; } /* Bottom-Left */
        .block-4 { grid-column: 3 / 4; grid-row: 3 / 4; } /* Bottom-Right */
        .block-5 { grid-column: 2 / 3; grid-row: 1 / 2; } /* Top-Middle */


        /* Responsive adjustments */
        @media (max-width: 1200px) {
            .dashboard-container {
                grid-template-columns: repeat(2, 1fr);
                grid-template-rows: auto; /* Allow rows to size based on content */
                height: auto;
                width: 98vw;
            }
            .main-trend {
                grid-column: 1 / 3; /* Span two columns */
                grid-row: auto;
                max-width: none;
                padding: 30px;
            }
            .dashboard-block {
                grid-column: auto;
                grid-row: auto;
                padding: 20px;
            }
            .dashboard-block h2 {
                font-size: 1.3em;
            }
            .dashboard-block li {
                font-size: 0.9em;
            }
            .main-trend h1 {
                font-size: 2.5em;
            }
            .main-trend ul {
                font-size: 1em;
            }
        }

        @media (max-width: 768px) {
            .dashboard-container {
                grid-template-columns: 1fr; /* Single column */
                grid-template-rows: auto;
                gap: 15px;
            }
            .main-trend {
                grid-column: 1 / 2;
                grid-row: auto;
                padding: 20px;
            }
            .dashboard-block {
                grid-column: 1 / 2;
                grid-row: auto;
            }
            body {
                padding: 10px;
            }
            .dashboard-container::before {
                top: -10px;
                left: -10px;
                right: -10px;
                bottom: -10px;
            }
            .main-trend h1 {
                font-size: 1.8em;
            }
            .main-trend ul {
                font-size: 0.9em;
            }
        }
    </style>
    <link href="https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700&display=swap" rel="stylesheet">
</head>
