    <script>
        // Function to update current time in the header
        function updateTime() {
            const now = new Date();
            const options = {
                year: 'numeric', month: '2-digit', day: '2-digit',
                hour: '2-digit', minute: '2-digit', second: '2-digit',
                hour12: false
            };
            const formattedTime = now.toLocaleString('ko-KR', options);
            document.getElementById('current-time').textContent = formattedTime.replace(/\. /g, '.').replace(/\.$/, '');
        }

        // Function to update the "Last Updated" date in the footer
        function updateLastUpdated() {
            const now = new Date();
            const options = {
                year: 'numeric', month: '2-digit', day: '2-digit',
                hour: '2-digit', minute: '2-digit', hour12: false
            };
            // Format to YYYY.MM.DD HH:MM
            const formattedDate = now.toLocaleString('ko-KR', options).replace(/\. /g, '.').replace(/\.$/, '').split(' ')[0] + ' ' + now.toLocaleTimeString('ko-KR', {hour: '2-digit', minute: '2-digit', hour12: false});
            document.getElementById('last-updated').textContent = formattedDate;
        }

        // Initialize and set interval for time updates
        updateTime();
        updateLastUpdated();
        setInterval(updateTime, 1000); // Update every second
    </script>
</body>
